import React, { useState, useEffect, useRef } from 'react'
import useData from './data';
import { useTableContext } from './Provider';
import { pageLimit } from './data';
import useIntersectionObserver from './useIntersectionObserver';

function InfiniteScroll({children}) {
  const [page,setPage] = useState(0)
  const { loading, error, tableData, total } = useData(page);
  const[hasMore, setHasMore] = useState(false)
  const { setTableData, searchedData } = useTableContext()
  const loaderRef = useIntersectionObserver(() => {
    // if(tableData && tableData.length > 0 &&  searchedData.length < total && hasMore) {
    if(tableData && tableData.length > 0 &&  searchedData.length < total && hasMore) {
    console.log('>>>>', page)
    console.log('tab', tableData)
    setPage(page => page + 1)
    }
  },{ threshold: 1}, hasMore)

  useEffect(() => {
   if(tableData) {
      setTableData(tableData)
      if(tableData.length === total) {
        setHasMore(false)
        return
      }
      if(tableData.length < total) {
        setHasMore(true)
      }
   }
  },[tableData])

    return (
        <>
        {children}
        {<div ref={loaderRef}>...Loading</div>}
        </>
    )
}

export default InfiniteScroll
